2631	\begin{lemma}
2632	[Hom into an injective preserves exactness and quasi-isomorphisms]
2633	  \label{lem:hom_into_injective_exact}
2634	  \lean{AlgebraicGeometry.preadditiveYoneda_obj_preservesFiniteColimits_of_injective,
2635	    AlgebraicGeometry.quasiIso_map_preadditiveYoneda_of_injective}
2636	  \uses{lem:injective_of_adjoint}
2637	  Let \(\mathcal{A}\) be an abelian category and \(I\) an injective object. Then the
2638	  contravariant hom functor \(\operatorname{Hom}(-, I) : \mathcal{A}^{\mathrm{op}} \to
2639	  \mathrm{Ab}\) is exact: it is automatically left exact (preserves finite limits), and
2640	  injectivity of \(I\) makes it carry epimorphisms to epimorphisms, so it preserves
2641	  finite colimits and hence preserves homology. Consequently \(\operatorname{Hom}(-, I)\)
2642	  carries quasi-isomorphisms of chain complexes in \(\mathcal{A}^{\mathrm{op}}\) to
2643	  quasi-isomorphisms of the \(\operatorname{Hom}\)-cochain complexes. Both statements
2644	  are for a general abelian category, the right generality for reuse in
2645	  Lemma~\ref{lem:injective_cech_acyclic}. The mechanism --- a right adjoint / exact
2646	  contravariant functor preserves the relevant exactness --- is the same homological
2647	  principle behind Lemma~\ref{lem:injective_of_adjoint}.
2648	\end{lemma}
